script.text:

function init$FormBankAccount(f) {
  setObjectFormHidden(f, 'ma_dvcs', f.grid._bankAccountUnit);
  f._controlFocus = f.getItem('tk');
}
function active$FormBankAccount(f) {
  f.add_onResponseComplete(on$FormBankAccount$ResponseComplete);  
  if (f._action == 'New' && f.grid._bankAccountUnit) {
    var o = f.getItem('ma_dvcs');
    o.value = f._unitCode;
    f.getItem('ten_dvcs%l').value = f._unitName;
    f._setReadOnly(f.getItem('ma_dvcs'), true);
  }  
}
function close$FormBankAccount(f) {try {f.remove_onResponseComplete(on$FormBankAccount$ResponseComplete)} catch (ex) {}}
function onChange$Bank$BankCode(o) {
  var c = 'ma_nh', f = o.parentForm;
  if ($func.trim(f.getItemValue(c))) o.parentForm.request('Bank', 'Bank', [c]);
}
function on$FormBankAccount$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'tknh');
      break;
    case 'Bank':
      f.setItemValues('ten_nh, ten_nh2, tinh_thanh, phone, fax', [result[0].Value, result[1].Value, result[2].Value, result[3].Value, result[4].Value);
      break;
    default:
      break;
  }
}
function setObjectFormHidden(f, c, b) {
  var o = f.getItem(c);
  o.field.AllowNulls = !b;
  if (b) {
    var grandNode = o.parentNode.parentNode;
    Sys.UI.DomElement.addCssClass(grandNode, 'Required');
    Sys.UI.DomElement.addCssClass(grandNode, f._id);
  }
  if (b) {if (!f._controlFocus) f._controlFocus = o;}
  else $common.setVisible(o.parentNode.parentNode.parentNode, false);
}

      &ScriptIrregular;
